using System;
using System.Diagnostics;
using System.IO;

public class PdfGenerator
{
    private const string WkHtmlToPdfPath = "path_to_wkhtmltopdf"; // Replace with the actual path to wkhtmltopdf executable

    public void GeneratePdf(string inputHtml, string outputPdf, string pageSize, string orientation)
    {
        var processStartInfo = new ProcessStartInfo
        {
            FileName = WkHtmlToPdfPath,
            Arguments = $"{inputHtml} -O {outputPdf} --page-size={pageSize} --orientation={orientation}",
            RedirectStandardOutput = true,
            UseShellExecute = false,
            CreateNoWindow = true
        };

        using (var process = new Process { StartInfo = processStartInfo })
        {
            process.Start();
            process.WaitForExit();

            if (process.ExitCode != 0)
                throw new Exception("wkhtmltopdf failed to execute");
        }
    }
}